static const char __pyx_k_GeckoDecoderLayer_class_for_the[] = "GeckoDecoderLayer class for the model.\n\n    This class implements a gecko decoder layer with self-attention and MLP components,\n    and optional LoRA (Low-Rank Adaptation) support.\n\n    Attributes:\n        hidden_size (int): Size of the hidden layer.\n        jit_trace (bool): Whether to use JIT tracing.\n        self_attn (GeckoAttention): Gecko self-attention block.\n        mlp (GeckoMLP): Gecko MLP block.\n        add (mtk_quantization.pytorch.functional.Add): Addition function for quantization.\n        add2 (mtk_quantization.pytorch.functional.Add): Second addition function for quantization.\n        expected_attn_lora_inputs (int): Expected number of LoRA inputs for attention.\n        expected_mlp_lora_inputs (int): Expected number of LoRA inputs for MLP.\n\n    Methods:\n        __init__(config, lora, jit_trace, layer_idx, attn_class, mlp_class, norm_class, parallel_lora,             exclude_input_norm):\n            Initialize the GeckoDecoderLayer.\n        forward(hidden_states, mask, cos, sin, past_key, past_value, *lora_inputs): Forward pass for the decoder layer.\n    ";
static const char __pyx_k_GeckoTail_class_for_the_tail_of[] = "GeckoTail class for the tail of the model.\n\n    Attributes:\n        norm (nn.Module): The normalization layer.\n        lm_head (nn.Linear): The linear layer for language modeling.\n        tanh_mul (mtk_quantization.pytorch.functional.Mul): The multiplication function for tanh scaling.\n        tanh_div (mtk_quantization.pytorch.functional.Div): The division function for tanh scaling.\n        support_quant_stub (bool): Whether quantizer stub is supported.\n        hidden_states (mtk_quantization.pytorch.functional.QuantizerStub): The quantizer stub for hidden states.\n        device_list (list): The list of devices.\n\n    Methods:\n        __init__(config, chunk_idx, dtype, jit_trace, norm_class, distribute_layers): Initialize the GeckoTail.\n        scaled_tanh(hidden_states, scale): Apply scaled tanh activation.\n        forward(hidden_states): Forward pass for the tail of the model.\n    ";
